using System.Text;
using VisualRelay.Core.Configuration;
using VisualRelay.Domain;

namespace VisualRelay.Core.Execution;

public sealed partial class RelayDriver
{
    /// <summary>
    /// On resume, restores the flagged working tree from a flagged-work bundle
    /// before re-entering the flagged stage. Only for mid-pipeline stages (5–10).
    /// Returns the (possibly adjusted) firstStageToRun and a non-null flagged
    /// outcome when the restore fails unresolvably.
    /// </summary>
    private async Task<(int firstStageToRun, RelayTaskOutcome? flaggedOutcome)> RestoreFlaggedWorkIfNeededAsync(
        string rootPath,
        string taskId,
        string taskDirectory,
        int firstStageToRun,
        StringBuilder ledger,
        List<StageStatusEntry> statusEntries,
        CancellationToken ct)
    {
        if (!_options.Resume || firstStageToRun is < 5 or > 10)
            return (firstStageToRun, null);

        // Only attempt restore when a bundle exists — resume proceeds normally
        // for older tasks that flagged before snapshots were introduced.
        var bundlePath = Path.Combine(taskDirectory, FlaggedWorkStore.BundleFileName);
        if (!File.Exists(bundlePath))
            return (firstStageToRun, null);

        var restoreResult = await FlaggedWorkStore.RestoreAsync(
            rootPath, taskId, taskDirectory, _dependencies.GitInvoker, ct);

        if (restoreResult.IsUnrestorable)
        {
            FlaggedWorkStore.Delete(taskDirectory);
            ledger.AppendLine("> **Resume**: flagged-work bundle not restorable — starting fresh from stage 1.");
            ledger.AppendLine();
            return (1, null);
        }

        if (restoreResult.HasConflicts)
        {
            return await ResolveConflictsAsync(
                rootPath, taskId, taskDirectory, firstStageToRun,
                restoreResult.ConflictedFiles, ledger, statusEntries, ct);
        }

        // Clean apply — proceed to the flagged stage.
        return (firstStageToRun, null);
    }

    private async Task<(int firstStageToRun, RelayTaskOutcome? flaggedOutcome)> ResolveConflictsAsync(
        string rootPath,
        string taskId,
        string taskDirectory,
        int firstStageToRun,
        IReadOnlyList<string> conflictedFiles,
        StringBuilder ledger,
        List<StageStatusEntry> statusEntries,
        CancellationToken ct)
    {
        const int maxAttempts = 3;

        for (int attempt = 1; attempt <= maxAttempts; attempt++)
        {
            var conflictList = string.Join("\n", conflictedFiles.Select(f => $"- `{f}`"));
            var systemPrompt = $$"""
You are resolving merge conflicts from resuming a flagged task. Conflict markers
(<<<<<<< / ======= / >>>>>>>) are present in the listed files. The task is being
re-applied onto a newer HEAD, and the conflicts come from overlapping upstream changes.

Resolve every conflict in every listed file so the intended feature is preserved
and adapted to the upstream changes. Do NOT commit; just edit the files in place.

Conflicted files:
{{conflictList}}

Task ledger (for context on the intended changes):
{{ledger}}
""";

            var invocation = new StageInvocation(
                Stage: new RelayStageDefinition(firstStageToRun, "Resolve conflicts", "cheap", "agent", "", "",
                    systemPrompt, "{}"),
                Tier: "cheap",
                RunId: $"resume-{taskId}",
                TargetRoot: rootPath,
                TaskName: taskId,
                TaskInput: $"Resolve conflicts for task {taskId}",
                LedgerSoFar: ledger.ToString(),
                Manifest: conflictedFiles,
                LogSources: [],
                TraceDirectory: Path.Combine(taskDirectory, $"resolve-conflicts-attempt{attempt}"),
                ReportFile: Path.Combine(taskDirectory, $"resolve-conflicts-attempt{attempt}.report.json"),
                MaxTurns: 10);

            await _dependencies.SubagentRunner.RunAsync(invocation, ct);

            // Stage resolved files: after git cherry-pick --quit the index
            // retains unmerged entries; ls-files -u reads the index, so the
            // agent's working-tree edits must be staged first.
            await _dependencies.GitInvoker.RunAsync(rootPath, ["add", "-A"], ct);

            // Check for remaining conflicts.
            var unmergedResult = await _dependencies.GitInvoker.RunAsync(
                rootPath, ["ls-files", "-u"], ct);
            var hasConflicts = unmergedResult.ExitCode == 0
                && !string.IsNullOrWhiteSpace(unmergedResult.Output);

            if (!hasConflicts)
            {
                ledger.AppendLine($"> **Resume**: conflicts resolved (attempt {attempt}).");
                ledger.AppendLine();
                return (firstStageToRun, null);
            }

            ledger.AppendLine($"> **Resume**: conflicts remain after resolution attempt {attempt}.");
            ledger.AppendLine();
        }

        // Exhausted budget — flag.
        var outcome = await FlagAsync(rootPath, $"resume-{taskId}", taskId, taskDirectory,
            firstStageToRun, "resume conflict unresolved",
            $"Conflicts remain in {conflictedFiles.Count} file(s) after {maxAttempts} resolution attempts: {string.Join(", ", conflictedFiles)}",
            statusEntries, ct);
        return (0, outcome);
    }
}

using VisualRelay.Core.Execution;
using VisualRelay.Domain;

namespace VisualRelay.Tests;

public sealed partial class RelayDriverResumeTests
{
    [Fact]
    public async Task Driver_Resume_RestoresWork_DeletesBundleOnCommit()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("exit 0", [], enableFixVerify: false);
        repo.WriteTask("resume-driver", "# Resume driver\n");
        InitTestRepo(repo.Root);

        // Run 1: flag at stage 6 (Implement).
        var flagRunner = new FlagAtStageSubagentRunner(flagAtStage: 6);
        var driver1 = new RelayDriver(
            RelayDriverDependencies.ForTests(flagRunner, new ScriptedTestRunner(
                new TestRunResult(1, "red")), new InMemoryRelayEventSink()),
            RelayDriverOptions.NoGitCommit);
        var outcome1 = await driver1.RunTaskAsync(repo.Root, "resume-driver");
        Assert.Equal(RelayTaskOutcomeStatus.Flagged, outcome1.Status);

        var taskDir = Path.Combine(repo.Root, ".relay", "resume-driver");
        var bundlePath = Path.Combine(taskDir, "flagged-work.bundle");
        Assert.True(File.Exists(bundlePath), "Bundle should exist after flag");

        // Run 2: resume — should restore flagged work and complete.
        var happyRunner = new ScriptedSubagentRunner();
        var driver2 = new RelayDriver(
            RelayDriverDependencies.ForTests(happyRunner, new ScriptedTestRunner(
                new TestRunResult(0, "green")), new InMemoryRelayEventSink()),
            new RelayDriverOptions(CreateGitCommit: false, Resume: true));
        var outcome2 = await driver2.RunTaskAsync(repo.Root, "resume-driver");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome2.Status);

        // Bundle must be deleted on successful commit.
        Assert.False(File.Exists(bundlePath), "Bundle should be deleted on commit");
    }

    [Fact]
    public async Task Driver_Resume_RestoresWork_OntoAdvancedBase()
    {
        using var repo = TestRepository.Create();
        repo.WriteConfig("exit 0", [], enableFixVerify: false);
        repo.WriteTask("resume-adv", "# Advanced base\n");
        InitTestRepo(repo.Root);

        // Run 1: flag at stage 6.
        var flagRunner = new FlagAtStageSubagentRunner(flagAtStage: 6);
        var driver1 = new RelayDriver(
            RelayDriverDependencies.ForTests(flagRunner, new ScriptedTestRunner(
                new TestRunResult(1, "red")), new InMemoryRelayEventSink()),
            RelayDriverOptions.NoGitCommit);
        await driver1.RunTaskAsync(repo.Root, "resume-adv");

        var taskDir = Path.Combine(repo.Root, ".relay", "resume-adv");
        var bundlePath = Path.Combine(taskDir, "flagged-work.bundle");
        Assert.True(File.Exists(bundlePath));

        // Advance HEAD with an unrelated commit.
        File.WriteAllText(Path.Combine(repo.Root, "unrelated.txt"), "unrelated");
        TestGit.Run(repo.Root, "add", "unrelated.txt");
        TestGit.Run(repo.Root, "commit", "-m", "unrelated commit");

        // Run 2: resume onto advanced base.
        var happyRunner = new ScriptedSubagentRunner();
        var driver2 = new RelayDriver(
            RelayDriverDependencies.ForTests(happyRunner, new ScriptedTestRunner(
                new TestRunResult(0, "green")), new InMemoryRelayEventSink()),
            new RelayDriverOptions(CreateGitCommit: false, Resume: true));
        var outcome2 = await driver2.RunTaskAsync(repo.Root, "resume-adv");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome2.Status);
        Assert.False(File.Exists(bundlePath), "Bundle should be deleted on commit");
    }

    [Fact]
    public async Task Driver_Resume_DoesNotRestore_WhenNotMidPipeline()
    {
        // Flag at stage 3 (pre-code) — resume should NOT restore.
        using var repo = TestRepository.Create();
        repo.WriteConfig("exit 0", [], enableFixVerify: false);
        repo.WriteTask("resume-s3", "# Stage 3 resume\n");
        InitTestRepo(repo.Root);

        var flagRunner = new FlagAtStageSubagentRunner(flagAtStage: 3);
        var driver1 = new RelayDriver(
            RelayDriverDependencies.ForTests(flagRunner, new ScriptedTestRunner(),
                new InMemoryRelayEventSink()),
            RelayDriverOptions.NoGitCommit);
        var outcome1 = await driver1.RunTaskAsync(repo.Root, "resume-s3");
        Assert.Equal(RelayTaskOutcomeStatus.Flagged, outcome1.Status);

        var taskDir = Path.Combine(repo.Root, ".relay", "resume-s3");
        var bundlePath = Path.Combine(taskDir, "flagged-work.bundle");
        if (File.Exists(bundlePath))
            File.Delete(bundlePath); // bundle may or may not exist; regardless, resume skips restore

        // Resume from stage 3: restore is gated to 5-10 only.
        var happyRunner = new ScriptedSubagentRunner();
        var driver2 = new RelayDriver(
            RelayDriverDependencies.ForTests(happyRunner, new ScriptedTestRunner(
                new TestRunResult(1, "red"), new TestRunResult(0, "green")),
                new InMemoryRelayEventSink()),
            new RelayDriverOptions(CreateGitCommit: false, Resume: true));
        var outcome2 = await driver2.RunTaskAsync(repo.Root, "resume-s3");
        Assert.Equal(RelayTaskOutcomeStatus.Committed, outcome2.Status);
    }

    private static void InitTestRepo(string root)
    {
        TestGit.Run(root, "init", "-b", "main");
        TestGit.Run(root, "config", "user.email", "test@test");
        TestGit.Run(root, "config", "user.name", "Test");
        File.WriteAllText(Path.Combine(root, ".gitignore"), ".relay/*\n");
        TestGit.Run(root, "add", ".gitignore");
        TestGit.Run(root, "commit", "-m", "initial");
    }
}

